const fs = require('fs');
const path = require('path');

function readLogFile(filename, callback) {
  const logsDirectory = path.resolve(__dirname, 'logs');
  const filePath = path.join(logsDirectory, path.basename(filename));

  fs.readFile(filePath, 'utf8', (err, data) => {
    if (err) {
      return callback(new Error('Error reading file or file does not exist.'));
    }
    callback(null, data);
  });
}

// Example usage
readLogFile('example.log', (err, data) => {
  if (err) {
    console.error(err.message);
  } else {
    console.log(data);
  }
});